#include <stdio.h>

int subArrayRanges(int* nums, int numsSize) {
    int sum = 0;
    for (int i = 0; i < numsSize; i++) {
        int smallest = nums[i];
        int largest = nums[i];
        for (int j = i; j < numsSize; j++) {
            smallest = (smallest < nums[j]) ? smallest : nums[j];
            largest = (largest > nums[j]) ? largest : nums[j];
            sum += largest - smallest;
        }
    }
    return sum;
}

int main() {
    int nums[] = {1, 2, 3};
    int numsSize = sizeof(nums) / sizeof(nums[0]);
    printf("The sum of subarray ranges is: %d\n", subArrayRanges(nums, numsSize));
    return 0;
}

