#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    long long subArrayRanges(vector<int>& nums) {
        int n = nums.size();
        long long sum = 0;
        for (int i = 0; i < n; i++) {
            int smallest = nums[i];
            int largest = nums[i];
            for (int j = i; j < n; j++) {
                smallest = min(smallest, nums[j]);
                largest = max(largest, nums[j]);
                sum += (long long)(largest - smallest);
            }
        }
        return sum;
    }
};

int main() {
    vector<int> nums = {1, 2, 3};
    Solution sol;
    cout << "The sum of subarray ranges is: " << sol.subArrayRanges(nums) << endl;
    return 0;
}

