import java.util.*;

public class Solution {
    public long subArrayRanges(int[] nums) {
        int n = nums.length;
        long sum = 0;
        for (int i = 0; i < n; i++) {
            int smallest = nums[i];
            int largest = nums[i];
            for (int j = i; j < n; j++) {
                smallest = Math.min(smallest, nums[j]);
                largest = Math.max(largest, nums[j]);
                sum += (long)(largest - smallest);
            }
        }
        return sum;
    }
}

public class Main {
    public static void main(String[] args) {
        int[] nums = {1, 2, 3};
        Solution sol = new Solution();
        System.out.println("The sum of subarray ranges is: " + sol.subArrayRanges(nums));
    }
}

